module.exports = { 'alta-via-dolomitica': { subtitle: 'Dal Lago di Braies a Belluno lungo alcune tra le montagne piu significative delle Dolomiti.', technical: { percorso: 'Dal Lago di Braies (Tre Cime Dolomiti / Alta Pusteria) fino a Belluno.', numeroTappe: 11, lunghezzaKm: '125 km circa', dislivelloSalitaTotale: '7.300 m', dislivelloDiscesaTotale: '8.400 m', dislivelloSalitaMassimo: '1.070 m (Fanes - Lagazuoi, III tappa)', dislivelloDiscesaMassimo: '1.900 m (Marmol - Belluno, ultima tappa)', quotaMassima: 'Rifugio Lagazuoi, 2.752 m', quotaMinima: 'Belluno, 389 m (localita Case Bortot, 568 m)', gruppiDolomitici: '11', aperturaRifugi: 'Giugno - Settembre', segnaletica: 'Buona', periodoConsigliato: 'Giugno - Settembre' }, intro: 'L\'Alta Via 1 delle Dolomiti e uno dei trekking piu spettacolari e celebri al mondo. Lunga circa 125 km, attraversa il cuore delle Dolomiti dal Lago di Braies fino a Belluno, con paesaggi che cambiano di valle in valle.', classicStagesNote: 'Il percorso classico viene spesso suddiviso in 11 tappe principali.', galleryImages: [ 'trails/alta-via-1_carosello_2.jpg', 'trails/Rifugio-Lagazuoi.webp'
], stages: [ { titolo: 'Lago di Braies - Rifugio Biella', tempo: '~3,5 - 4 ore', dislivello: '+900m / -60m', descrizione: 'Si parte dalle acque smeraldo del Lago di Braies. Salita costante nel vallone del Nabige Loch fino alla Forcella Sora Forno, poi breve discesa al Rifugio Biella ai piedi della Croda del Becco.' }, { titolo: 'Rifugio Biella - Rifugio Fanes (o Lavarella)', tempo: '~4,5 - 5 ore', dislivello: '+550m / -800m', descrizione: 'Tappa panoramica sull\'altopiano di Sennes. Discesa verso Pederu e risalita nella Val di Fanes fino ai rifugi Fanes o Lavarella.' }, { titolo: 'Rifugio Fanes - Rifugio Lagazuoi', tempo: '~5 - 6 ore', dislivello: '+1.000m / -300m', descrizione: 'Tra le tappe piu spettacolari: Forcella del Lago, Lago di Lagazuoi e salita finale al Rifugio Lagazuoi (2.752 m), area ricca di testimonianze della Prima Guerra Mondiale.' }, { titolo: 'Rifugio Lagazuoi - Rifugio Nuvolau', tempo: '~5 - 6 ore', dislivello: '+600m / -800m', descrizione: 'Discesa verso Passo Falzarego, passaggio per le Cinque Torri e salita al Rifugio Nuvolau, storico punto panoramico con vista a 360 gradi.' }, { titolo: 'Rifugio Nuvolau - Rifugio Citta di Fiume', tempo: '~4,5 - 5 ore', dislivello: '+250m / -600m', descrizione: 'Discesa verso Passo Giau e traversata sotto la Ra Gusela e le pendici del Pelmo fino al Rifugio Citta di Fiume.' }, { titolo: 'Rifugio Citta di Fiume - Rifugio Coldai', tempo: '~3 - 4 ore', dislivello: '+600m / -300m', descrizione: 'Ingresso nel gruppo del Civetta, passaggio dal Passo Staulanza e salita finale al Rifugio Coldai, vicino al suggestivo Lago Coldai.' }, { titolo: 'Rifugio Coldai - Rifugio Vazzoler', tempo: '~4 - 5 ore', dislivello: '+350m / -750m', descrizione: 'Tappa maestosa sotto la parete nord-ovest del Civetta. Passaggio dal Rifugio Tissi e discesa al Rifugio Vazzoler.' }, { titolo: 'Rifugio Vazzoler - Rifugio Carestiato', tempo: '~4 - 5 ore', dislivello: '+550m / -400m', descrizione: 'Dai versanti del Civetta al gruppo della Moiazza tra mughi, ghiaioni e tratti esposti, fino al Rifugio Carestiato.' }, { titolo: 'Rifugio Carestiato - Rifugio Pramperet', tempo: '~4,5 - 5,5 ore', dislivello: '+500m / -450m', descrizione: 'Dal Passo Duran verso il Parco Nazionale delle Dolomiti Bellunesi, in ambiente piu selvaggio fino al Rifugio Pramperet.' }, { titolo: 'Rifugio Pramperet - Rifugio Pian de Fontana', tempo: '~3 - 4 ore', dislivello: '+450m / -650m', descrizione: 'Tappa breve ma intensa con salita alla Forcella de Zita Sud e lunga discesa erbosa verso il Rifugio Pian de Fontana.' }, { titolo: 'Rifugio Pian de Fontana - Belluno (La Pissa)', tempo: '~4 - 5 ore', dislivello: '+150m / -1.100m', descrizione: 'Ultima tappa quasi tutta in discesa via Rifugio Bianchet e Val Vescova, fino a La Pissa con collegamenti autobus per Belluno.' } ] } };

