'use strict';

const fs = require('fs');
const path = require('path');
const multer = require('multer');

const uploadDir = path.join(__dirname, '..', 'public', 'images', 'facilities');
fs.mkdirSync(uploadDir, { recursive: true });

const storage = multer.diskStorage({
  destination: function (_req, _file, cb) {
    cb(null, uploadDir);
  },
  filename: function (req, file, cb) {
    const ext = path.extname(file.originalname || '').toLowerCase();
    const safeEmail = String((req.user && req.user.email) || 'ristoratore')
      .replace(/[^a-zA-Z0-9._-]/g, '_');
    const safeName = String(file.originalname || 'immagine')
      .replace(/\.[^/.]+$/, '')
      .replace(/[^a-zA-Z0-9._-]/g, '_')
      .slice(0, 40);
    cb(null, safeEmail + '-' + safeName + '-' + Date.now() + ext);
  }
});

const fileFilter = function (_req, file, cb) {
  const allowed = ['image/png', 'image/jpeg'];
  if (!allowed.includes(file.mimetype)) {
    return cb(new Error('Formato non valido: carica solo PNG o JPG/JPEG'));
  }
  cb(null, true);
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: 4 * 1024 * 1024
  }
});

function uploadFacilityImage(req, res, next) {
  upload.single('immagine_struttura')(req, res, function (err) {
    if (err) {
      const message = err.code === 'LIMIT_FILE_SIZE'
        ? 'Immagine troppo grande: massimo 4MB'
        : err.message;
      return res.redirect('/gestione?errore=' + encodeURIComponent(message));
    }
    next();
  });
}

module.exports = { uploadFacilityImage };

'use strict';

const fs = require('fs');
const path = require('path');
const multer = require('multer');

const uploadDir = path.join(__dirname, '..', 'public', 'images', 'facilities');
fs.mkdirSync(uploadDir, { recursive: true });

const storage = multer.diskStorage({
  destination: function (_req, _file, cb) {
    cb(null, uploadDir);
  },
  filename: function (req, file, cb) {
    const ext = path.extname(file.originalname || '').toLowerCase();
    const safeEmail = String((req.user && req.user.email) || 'ristoratore')
      .replace(/[^a-zA-Z0-9._-]/g, '_');
    const safeName = String(file.originalname || 'immagine')
      .replace(/\.[^/.]+$/, '')
      .replace(/[^a-zA-Z0-9._-]/g, '_')
      .slice(0, 40);
    cb(null, safeEmail + '-' + safeName + '-' + Date.now() + ext);
  }
});

const fileFilter = function (_req, file, cb) {
  const allowed = ['image/png', 'image/jpeg', 'image/webp'];
  if (!allowed.includes(file.mimetype)) {
    return cb(new Error('Formato non valido: carica solo PNG, JPG/JPEG o WEBP'));
  }
  cb(null, true);
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: 4 * 1024 * 1024
  }
});

function uploadFacilityImage(req, res, next) {
  upload.single('immagine_struttura')(req, res, function (err) {
    if (err) {
      const message = err.code === 'LIMIT_FILE_SIZE'
        ? 'Immagine troppo grande: massimo 4MB'
        : err.message;
      return res.redirect('/gestione?errore=' + encodeURIComponent(message));
    }
    next();
  });
}

module.exports = { uploadFacilityImage };

'use strict';

(function () {
  var mapEl = document.querySelector('[data-gpx-map]');
  if (!mapEl || typeof L === 'undefined') {
    return;
  }

  var gpxUrl = mapEl.getAttribute('data-gpx') || '';
  var noteEl = document.querySelector('[data-gpx-note]');

  function showNote(message) {
    if (noteEl) {
      if (message) {
        noteEl.textContent = message;
      }
      noteEl.hidden = false;
    }
  }

  if (!gpxUrl) {
    showNote('Traccia GPX non disponibile per questo cammino.');
    return;
  }

  fetch(gpxUrl)
    .then(function (res) {
      if (!res.ok) {
        throw new Error('Errore caricamento GPX');
      }
      return res.text();
    })
    .then(function (xmlText) {
      var parser = new DOMParser();
      var xml = parser.parseFromString(xmlText, 'application/xml');
      var trkpts = xml.getElementsByTagName('trkpt');
      var rtepts = xml.getElementsByTagName('rtept');
      var points = [];

      for (var i = 0; i < trkpts.length; i += 1) {
        var lat = parseFloat(trkpts[i].getAttribute('lat'));
        var lon = parseFloat(trkpts[i].getAttribute('lon'));
        if (!Number.isNaN(lat) && !Number.isNaN(lon)) {
          points.push([lat, lon]);
        }
      }

      if (!points.length && rtepts.length) {
        for (var j = 0; j < rtepts.length; j += 1) {
          var rLat = parseFloat(rtepts[j].getAttribute('lat'));
          var rLon = parseFloat(rtepts[j].getAttribute('lon'));
          if (!Number.isNaN(rLat) && !Number.isNaN(rLon)) {
            points.push([rLat, rLon]);
          }
        }
      }

      if (!points.length) {
        showNote('Traccia GPX non valida o vuota.');
        return;
      }

      var map = L.map(mapEl);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        maxZoom: 18,
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(map);

      var polyline = L.polyline(points, {
        color: '#f04c26',
        weight: 5,
        opacity: 0.85
      }).addTo(map);

      L.marker(points[0]).addTo(map).bindPopup('Partenza');
      L.marker(points[points.length - 1]).addTo(map).bindPopup('Arrivo');

      map.fitBounds(polyline.getBounds(), { padding: [20, 20] });
    })
    .catch(function () {
      showNote('Non riesco a caricare la traccia GPX in questo momento.');
    });
})();

