   /* Main Style File */
   /**
* Table of Contents:
*
* 1.0 - General Style
* 2.0 - Header Wrapper
* 3.0 - About Wrapper 
* 4.0 - Services Wrapper
* 5.0 - About Wrapper
* 6.0 - Services Wrapper
* 7.0 - client Section
* 8.0 - Team Wrapper
* 9.0 - footer Wrapper
* 10.0 - Pricing Wrapper
* 11.0 - Contact Css 
* 12.0 - Responsive Css 

* -----------------------------------------------------------------------------
*/
   /**
* 1.0 General Style
* -----------------------------------------------------------------------------
*/

   html {
       -webkit-font-smoothing: antialiased;
       -moz-font-smoothing: antialiased;
       font-smoothing: antialiased;
   }

   body {
       margin: 0;
       padding: 0;
       /*Default font size */
       font-size: 15px;
       font-family: 'Roboto Slab', serif;
       font-weight: 400;
       font-size: 100%;
       -webkit-font-smoothing: antialiased;
       -moz-font-smoothing: antialiased;
       font-smoothing: antialiased;
   }

   a,
   a:hover {
       text-decoration: none;
       transition: all 0.5s ease-in-out;
       color: #f04c26;
   }

   .container {
       max-width: 1131px;
       margin: auto;
   }

   .main_container {
       width: 100%;
       padding: 0;
   }

   .no-padding {
       padding: 0;
   }

   img {
       max-width: 100%;
   }

   .pagination>li>a,
   .pagination>li>span {
       float: none;
       padding: 10px 15px;
       color: #000;
       border: 0;
       font-size: 14px;
       background: transparent;
       margin: 0 2px;
   }

   .pagination>.active>a,
   .pagination>.active>a:focus,
   .pagination>.active>a:hover,
   .pagination>.active>span,
   .pagination>.active>span:focus,
   .pagination>.active>span:hover {
       background-color: #F04C26;
       border: 0;
       border-radius: 50px
   }

   .pagination>li>a:focus,
   .pagination>li>a:hover,
   .pagination>li>span:focus,
   .pagination>li>span:hover {
       color: #000;
       background-color: transparent;
       border: 0;
   }
   /* Variables related to App Theme */
   /**
* 2.0 Header Wrapper Start Here *
* -----------------------------------------------------------------------------
*/

   .header_wrapper {
       width: 100%;
       padding: 0;
   }

   .header_wrapper .header_top {
       background: #333333;
       padding: 20px 0;
       font-family: 'Open Sans', sans-serif;
   }

   .header_wrapper .header_top a.top_menu {
       color: #fff;
       font-size: 13px;
       padding-right: 20px;
       display: inline-block;
       padding-top: 5px;
   }

   .header_wrapper .header_top .fa {
       font-size: 20px;
       color: #fff;
       vertical-align: middle;
       margin-right: 5px;
   }

   .header_wrapper .header_top .pull-right .fa {
       margin: 0 10px;
   }

   .header_wrapper #menu {
       padding: 40px 0px;
       position: relative;
       z-index: 99;
   }

   .header_wrapper #menu .logo a {
       color: #f5b705;
       font-size: 25px;
   }

   .slider_wrapper {
       width: 100%;
       padding-top: 0px;
   }

   .slider_wrapper .overly_bg {
       background: rgba(0, 0, 0, 0.5);
       height: 100%;
   }

   .slider_wrapper .slider_text {
       display: block;
       padding: 50px;
       margin-top: 130px;
       background: rgba(0, 0, 0, 0.7);
       position: relative;
   }

   .slider_wrapper .slider_text h1 {
       font-size: 36px;
       color: #fff;
       text-transform: capitalize;
       margin: 0;
   }

   .slider_wrapper .slider_text p {
       font-size: 14px;
       color: #fff;
       line-height: 27px;
       font-family: open sans;
   }

   .slider_wrapper .slider_text .read_more_outer {
       background: #f5b705;
