    margin: 0;
    padding-right: 0;
    position: absolute;
    right: 0;
    top: 8px;
}

.header .navbar-default .navbar-form.navbar-right .input-group {
    display: flex;
    align-items: stretch;
    background: #ffffff;
    border-radius: 999px;
    box-shadow: 0 10px 24px rgba(0, 0, 0, 0.16);
    overflow: hidden;
}

.header .navbar-default .navbar-form.navbar-right .form-control {
    border: 0;
    box-shadow: none;
    height: 40px;
    padding: 8px 16px;
    font-size: 14px;
}

.header .navbar-default .navbar-form.navbar-right .btn {
    border: 0;
    background-color: #f04c26;
    color: #fff;
    height: 40px;
    padding: 0 16px;
}

.header .navbar-default .navbar-form.navbar-right .btn:hover {
    background-color: #d74320;
}

.header .navbar-default .navbar-form.navbar-right .fa {
    font-size: 16px;
}

.header .navbar-default .navbar-nav>li>a {
    color: #414141;
    font-size: 16px;
    font-weight: 500;
}

.header .navbar-default .navbar-nav>li>a:hover {
    color: #f04c26;
}

.header .navbar-default .navbar-nav>li>a.navbar-profile-link {
    display: inline-flex;
    align-items: center;
    gap: 8px;
}

.navbar-profile-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid #d6dce8;
}

.header .banner {
    cursor: grab;
    position: relative;
    min-height: 100%;
    display: flex;
    align-items: center;
    overflow: hidden;
    padding: 12px 0;
    background: transparent;
}

.header .banner::before {
    display: none;
}

.header .banner .banner-content {
    position: relative;
    z-index: 1;
}

.header .banner .banner-content .item {
    max-width: 760px;
    margin: 0 auto;
    padding: 0;
    border-radius: 0;
    background: transparent;
    border: 0;
    box-shadow: none;
    -webkit-backdrop-filter: none;
    backdrop-filter: none;
}

.header .banner .banner-content h1 {
    color: #f5f9f5;
    font-size: 72px;
    text-transform: uppercase;
    font-family: 'Dosis', sans-serif;
    font-weight: 800;
    letter-spacing: 0.04em;
    margin: 0 0 22px;
    text-align: left;
    line-height: 1.04;
}

.header .banner .banner-content .owl-prev {
    position: absolute;
    left: -14px;
    top: 50%;
    transform: translateY(-50%);
    background: rgba(255, 255, 255, 0.25) url("../images/arrow-leftBlack.png") center center no-repeat !important;
    font-size: 0 !important;
    height: 44px;
    width: 44px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.35);
    content: "";

}

.header .banner .banner-content .owl-next {
    background: rgba(255, 255, 255, 0.25) url("../images/arrow-rightBlack.png") center center no-repeat !important;
    content: "";
    font-size: 0 !important;
    height: 44px;
    position: absolute;
    right: -14px;
    top: 50%;
    transform: translateY(-50%);
    width: 44px;
    border-radius: 999px;
    border: 1px solid rgba(255, 255, 255, 0.35);
}

.header .banner .banner-content .owl-theme .owl-dots {
    display: none;
}
#header {
	height: auto;
	background-size: 100%;
	background-color: rgba(240, 76, 37, 0.1);
	background-image: url('../images/pattern-xv.png');
    font-family: 'Dosis', sans-serif;
}

/*======HEADER CSS ENDS====*/


/*====ABOUT CSS STARTS====*/

.about {
    background-color: #fff;
    margin-bottom: 65px;
}

.about .banner-heading p {
    color: #555655;
    padding: 0 200px 30px 200px;
    text-align: center;
    line-height: 26px;
}

.about .about-inner-content {
    text-align: center;
}

.about .about-inner-content p {
    font-size: 18px;
    text-transform: uppercase;
    font-weight: 500;
}

.about .about-image {
    text-align: center;
    margin-bottom: 10px;
}


/*======ABOUT CSS ENDS====*/


/*====VIDEO CSS STARTS====*/

.video {
    background-image: url(../images/banner-2.jpg);
    height: 450px;
    position: relative;
    background-repeat: no-repeat;
    background-position: center;
}

.video::after {
    position: absolute;
    background-color: rgba(0, 0, 0, 0.7);
    height: 100%;
    width: 100%;
    left: 0;
    top: 0;
    content: " ";
}

.video .play-video {
    text-align: center;
    margin-top: 170px;
}

.video .play-video img {
    position: relative;
    z-index: 1;
}

.video .play-video p {
    font-size: 28px;
    font-weight: 500;
    z-index: 999;
    color: #fff;
    position: relative;
    margin-top: 50px;
}

/*======VIDEO CSS ENDS====*/


/*====TRAIL CSS STARTS====*/

.trails .accordion1 {
    margin-left: 160px;
}

.trails .container-fluid {
    padding-right: 0;
    overflow: hidden;
    background-color: #f1f0f0;
}

.trails .panel-default>.panel-heading {
    background-color: #F04C26;
    color: #fff;
    border: 0;
    border-radius: 0;
    margin-bottom: 20px;
}

.trails .panel-title {
    font-size: 24px;
}

.trails .panel-group .panel {
    margin-bottom: 0;
    border-radius: 4px;
    border: 0;
}
/*DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDC0*/
.trails .accordion1 p {
    font-size: 16px;
    color: #555655;
    background-color: #fff;
    margin: 0;
    padding: 15px;
    margin-bottom: 20px;
}

.trails .panel-default>.panel-heading+.panel-collapse>.panel-body {
    border: 0;
}

.trails .panel {
    background-color: transparent;
}

.trails .panel-body {
    padding: 0;
}


/*======TRAILS CSS ENDS====*/


/*====GALLERY CSS STARTS====*/

.gallery {
    padding-bottom: 80px;
}

.gallery .gallery-image-2 {
    margin-top: 40px;
}

.gallery .gallery-image:hover .gallery-overlay,
.gallery .gallery-image-2:hover .gallery-overlay {
    opacity: 1;
    transition: all 0.3s ease-in-out;
    visibility: visible;
}

.gallery .gallery-image,
.gallery .gallery-image-2 {
    position: relative;
    display: inline-block;
}

.gallery .gallery-overlay {
    position: absolute;
    background: rgba(0, 0, 0, 0.72);
    z-index: 1;
    height: 100%;
    width: 100%;
    opacity: 0;
    visibility: hidden;
}

.gallery .gallery-overlay a {
    text-align: center;
}

.gallery .gallery-overlay a .fa {
    font-size: 20px;
    background: #fff;
    width: 50px;
    height: 50px;
    margin: auto;
    text-align: center;
    display: inherit;
    border-radius: 100%;
    line-height: 50px;
    position: absolute;
    color: #000;
    top: 90px;
    left: 0;
    right: 0;
}


/*======GALLERY CSS ENDS====*/


/*====BLOG CSS STARTS====*/

.blog {
    background-image: url('../images/blog-banner.jpg');
    padding-bottom: 50px;
    background-size: cover;
    background-position: center;
}

.blog .blog-heading {
    font-size: 22px;
    font-weight: 600;
    text-align: center;
    margin-top: 15px;
    color: #333333;
}

.blog .blog-textual-cont {
    color: #555655;
    text-align: center;
    font-size: 16px;
    padding: 0 30px;
}

.blog .blog-img {
    text-align: center;
    position: relative;
    display: inline-block;
}

.blog .blog-img img {
    display: inline;
    margin-top: -20px;
}

.blog .blog-inner {
    background-color: #fff;
}

.blog .read-more {
    font-size: 14px;
    width: 100%;
    display: block;
    text-align: center;
    text-transform: uppercase;
    color: #f04c25;
    padding: 5px 0;
    visibility: hidden;
}

.blog .blog-inner:hover .read-more {
    visibility: visible;
}

.blog .blog-inner:hover .blog-img .img-border {
    visibility: visible;
}

.blog .blog-inner .blog-img .img-border {
    visibility: hidden;
    height: 100%;
    width: 90%;
    position: absolute;
    top: -11px;
    left: 15px;
    border: 1px solid #fff;
}


/*======BLOG CSS ENDS====*/


/*====CHALLENGE CSS STARTS====*/

.challenge {
    background-image: url('../images/bg-texture.jpg');
    padding-bottom: 80px;
}

.challenge .heading span {
    text-transform: uppercase;
    color: #f04c25;
    font-weight: 700;
}

.challenge .heading {
    max-width: 440px;
    margin: auto;
    text-align: center;
    margin-top: 90px;
}

.challenge .heading h2 {
    line-height: 70px;
}

.challenge .challenge-text .font-16 {
    font-size: 16px;
    font-weight: 400;
    color: #555655;
    padding: 40px 250px;
    text-align: center;
}

.challenge .input-group .form-control {
    border: 0;
    box-shadow: none;
    background-color: transparent;
    border-bottom: 1px solid #333;
    border-radius: 0;
    font-size: 16px;
}

.challenge .input-group {
    width: 40%;
    margin: auto;
}

.challenge .input-group .form-control:last-child,
.challenge .input-group-addon:last-child,
.challenge .input-group-btn:first-child>.btn-group:not(:first-child)>.btn,
.input-group-btn:first-child>.btn:not(:first-child),
.challenge .input-group-btn:last-child>.btn,
input-group-btn:last-child>.btn-group>.btn,
.challenge .input-group-btn:last-child>.dropdown-toggle {
    border-top-left-radius: 4px;
    border-bottom-left-radius: 4px;
    left: 30px;
}

.challenge .btn-danger {
    background-color: #f04c25;
    height: 40px;
    width: 180px;
    border: 0;
    font-size: 16px;
    font-weight: 600;
    margin-top: -7px;
}





/*======CHALLENGE CSS ENDS====*/


