}

.footer .footer-content .social-icons ul {
    padding: 0;
}

.footer .footer-content .social-icons ul li {
    display: inline-block;
}

.footer .footer-content .social-icons {
    margin-top: 30px;
}

.footer .footer-content .social-icons li a .fa {
    color: #fff;
    width: 40px;
